from dataclasses import dataclass

@dataclass
class Triple:
    subject: str
    predicate: str
    object: str

# EVOLVE-BLOCK-START

def predict(triples: list[Triple]) -> str:
    if not triples:
        return ""
    phrases = []
    for t in triples:
        s, p, o = t.subject, t.predicate, t.object
        if p == "birthDate":
            phrase = f"{s} was born on {o}"
        elif p == "birthPlace":
            phrase = f"{s} was born in {o}"
        elif p == "height":
            phrase = f"{s} is {o} meters tall"
        elif p == "weight":
            phrase = f"{s} weighs {o}"
        elif p == "club":
            phrase = f"{s} plays for {o}"
        elif p == "currentclub":
            phrase = f"{s} currently plays for {o}"
        elif p == "position":
            phrase = f"{s} plays in the {o} position"
        elif p == "league":
            phrase = f"{s} competes in the {o} league"
        elif p == "manager":
            phrase = f"{s} is managed by {o}"
        elif p == "ground":
            phrase = f"{s} plays at {o}"
        else:
            phrase = f"{s} {p} {o}"
        phrases.append(phrase)
    if len(phrases) == 1:
        return phrases[0] + "."
    return ", ".join(phrases[:-1]) + ", and " + phrases[-1] + "."

